  ('elementary-0489de64-moex-00211', 'elementary-0489de64', 'elementary-0489de64-moex-113-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '小張駕駛汽油引擎小客車至大賣場購物，因車多找不到停車位，貪圖方便占用電動汽車充電專用停車位， 依停車場法，下列處置規定何者錯誤？', '["停車場經營業應通報主管機關或警察機關", "由主管機關吊扣小張駕駛執照1至3個月", "主管機關、警察機關或停車場經營業得逕行將小張之車輛移置至適當處所", "由主管機關處小張新臺幣6百元以上1千2百元以下罰鍰"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "06f4ea4edc6e", "answer_pdf_sha1": "9cdda496d42f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00212', 'elementary-0489de64', 'elementary-0489de64-moex-113-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '下列何者經參加直轄市、縣（市）主管機關公開程序取得拖吊業經營資格者，得申請於其停車場四周一定 區域範圍內，經營違規停車拖吊業務？', '["小貨車租賃業", "汽車貨運業", "汽車路線貨運業", "停車場經營業"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "06f4ea4edc6e", "answer_pdf_sha1": "9cdda496d42f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00213', 'elementary-0489de64', 'elementary-0489de64-moex-113-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '依鐵路法第56條之6規定，鐵路運轉中發生之事故及異常事件，應由下列何單位進行檢討？', '["交通部鐵道局", "交通部交通產業發展及國際事務司", "交通部路政及道安司", "交通部運輸研究所"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "06f4ea4edc6e", "answer_pdf_sha1": "9cdda496d42f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00214', 'elementary-0489de64', 'elementary-0489de64-moex-113-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '旅客無正當理由無票搭乘鐵路班車被查獲，除應補繳票價外，下列規定何者正確？', '["另支付票價50倍之違約金", "處新臺幣1千5百元以上7千5百元以下罰鍰", "另支付50%之票價", "併處票價10倍至30倍之罰鍰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "06f4ea4edc6e", "answer_pdf_sha1": "9cdda496d42f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00215', 'elementary-0489de64', 'elementary-0489de64-moex-113-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '大眾捷運系統營運機構為維護安全，下列何者非其權責？', '["對行車人員，應予有效之訓練與管理", "對行車事故，應蒐集資料調查研究，分析原因，並採取預防措施", "對行車及路線、場、站設施，應妥善管理維護", "對維護路線、場、站及行車秩序與旅客安全，設置捷運警察"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "06f4ea4edc6e", "answer_pdf_sha1": "9cdda496d42f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00216', 'elementary-0489de64', 'elementary-0489de64-moex-113-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '民間自行規劃大眾捷運系統者，其大眾捷運系統規劃報告書應向下列何機關提出？', '["直轄市或縣（市）政府", "交通部", "內政部", "行政院"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "06f4ea4edc6e", "answer_pdf_sha1": "9cdda496d42f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00217', 'elementary-0489de64', 'elementary-0489de64-moex-113-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '台電公司租用民營直升機清洗輸電線路絕緣礙子，依民用航空法規定，該項飛航業務屬於下列何者？', '["民用航空運輸業", "航空貨運承攬業", "普通航空業", "航空站地勤業"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "06f4ea4edc6e", "answer_pdf_sha1": "9cdda496d42f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00218', 'elementary-0489de64', 'elementary-0489de64-moex-113-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '依民營飛行場管理規則規定，申請設立民營飛行場，應檢附相關文件，下列申請程序何者正確？', '["向交通部民用航空局申請，經會同有關機關會勘合格，報請國防部核准後，始得籌設", "向交通部民用航空局申請，經會同有關機關會勘合格，報請交通部核准後，始得籌設", "向所在地縣市政府申請，經會同有關機關會勘合格，報請交通部核准後，始得籌設", "向所在地縣市政府申請，經會同有關機關會勘合格，報請交通部民用航空局核准後，始得籌設"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "06f4ea4edc6e", "answer_pdf_sha1": "9cdda496d42f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00219', 'elementary-0489de64', 'elementary-0489de64-moex-113-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '從事遙控無人機飛航活動，除經申請核准外，下列操作何者符合規定？', '["於禁（限）航區外，飛行高度距離地面300呎", "操作人同時操作2架遙控無人機", "於人群聚集或室外集會遊行上空飛航", "於日落後天空尚未全黑之暮光時段飛航"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "06f4ea4edc6e", "answer_pdf_sha1": "9cdda496d42f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL),
  ('elementary-0489de64-moex-00220', 'elementary-0489de64', 'elementary-0489de64-moex-113-5a5961d5', 'sub-elementary-0489de64-01', NULL, 'single_choice', '有關75歲以上年長者普通駕駛執照之管理規定，下列敘述何者錯誤？', '["自106年7月1日前已年滿75歲之駕駛人，其駕駛執照有效期間屆滿後，即為失效，應重新考領", "自106年7月1日後，新領或未逾75歲駕駛人已領有之普通駕駛執照有效期間至年滿75歲止，其後 應每滿3年換發一次", "年滿75歲駕駛人首次換照，得於有效期間屆滿前1個月至屆滿後3年內辦理", "年滿75歲申請汽車駕駛執照考驗者，應符合體格檢查及體能測驗合格基準，並檢附通過認知功能測驗 或無患有中度以上失智症證明文件，始得向公路監理機關申請考驗，及格後核發 3 年有效期間之駕駛 執照"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:58+00:00", "source_pdf_sha1": "06f4ea4edc6e", "answer_pdf_sha1": "9cdda496d42f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "512", "s": "0302", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "交通行政大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "交通行政"}'::jsonb, NULL)
